import React, { useState, useEffect, useRef } from 'react';
import { devicesApi } from '../lib/api';

const Terminal = () => {
  const [tabs, setTabs] = useState([]);
  const [activeTab, setActiveTab] = useState(null);
  const [devices, setDevices] = useState([]);
  const [showDeviceList, setShowDeviceList] = useState(false);
  const inputRef = useRef(null);

  const availableCommands = [
    'ls', 'ls -la', 'ls -l', 'pwd', 'cd', 'cd ..', 'cd ~',
    'whoami', 'hostname', 'date', 'uptime', 'uname', 'uname -a',
    'free', 'free -h', 'df', 'df -h', 'ip', 'ip a', 'ip addr', 'ip route',
    'ifconfig', 'ping', 'netstat', 'netstat -tuln', 'ss', 'ps', 'ps aux',
    'cat', 'cat /etc/passwd', 'cat /etc/hosts', 'systemctl', 'systemctl status',
    'history', 'clear', 'exit', 'help',
    '/export', '/system resource', '/interface print', '/ppp active print',
    'display version', 'display interface', 'display cpu', 'display memory'
  ];

  useEffect(() => { loadDevices(); }, []);

  const loadDevices = async () => {
    try {
      const response = await devicesApi.list();
      setDevices(response || []);
    } catch (error) {
      console.error('Error loading devices:', error);
    }
  };

  const openNewTab = (device) => {
    const existingTab = tabs.find(t => t.deviceId === device.id);
    if (existingTab) {
      setActiveTab(existingTab.id);
      setShowDeviceList(false);
      return;
    }

    const newTab = {
      id: Date.now(),
      deviceId: device.id,
      name: device.hostname || device.ip_address,
      ip: device.ip_address,
      port: device.port || 22,
      username: device.username || 'root',
      vendor: device.vendor || '',
      output: [
        '[LOR CGR Terminal v1.0]',
        'Dispositivo: ' + device.hostname,
        'IP: ' + device.ip_address + ' Porta: ' + (device.port || 22),
        'Digite "help" para ver comandos disponiveis',
        ''
      ],
      history: [],
      historyIndex: -1
    };

    setTabs(prev => [...prev, newTab]);
    setActiveTab(newTab.id);
    setShowDeviceList(false);
    appendOutput(newTab.id, newTab.username + '@' + newTab.name + ':~$ ');
  };

  const appendOutput = (tabId, text) => {
    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, output: [...t.output, text] } : t));
    setTimeout(() => {
      const terminal = document.getElementById('terminal-' + tabId);
      if (terminal) terminal.scrollTop = terminal.scrollHeight;
    }, 10);
  };

  const findCompletions = (input) => {
    if (!input.trim()) return [];
    return availableCommands.filter(cmd => cmd.toLowerCase().startsWith(input.toLowerCase()));
  };

  const sendCommand = (tabId, command) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab || !command.trim()) return;

    setTabs(prev => prev.map(t => t.id === tabId ? { ...t, history: [...t.history, command], historyIndex: -1 } : t));
    appendOutput(tabId, tab.username + '@' + tab.name + ':~$ ' + command);
    simulateCommand(tabId, command, tab);
  };

  const simulateCommand = (tabId, command, tab) => {
    const cmd = command.trim().toLowerCase();
    const args = command.trim().split(' ').slice(1);

    setTimeout(() => {
      let output = '';
      const isHuawei = (tab.vendor || '').toLowerCase().includes('huawei');
      const isMikrotik = (tab.vendor || '').toLowerCase().includes('mikrotik');

      if (isHuawei && cmd.startsWith('display')) {
        if (cmd.includes('version')) {
          output = 'Huawei Versatile Routing Platform Software\nVRP Version 8.231\nCopyright (C) Huawei Technologies Co., Ltd.';
        } else if (cmd.includes('interface')) {
          output = 'Interface                   PHY   Protocol  InUti OutUti\nGigabitEthernet0/0/0        up    up        0.01%  0.01%\nGigabitEthernet0/0/1        up    up        0.02%  0.01%';
        } else if (cmd.includes('cpu')) {
          output = 'CPU utilization: 15%';
        } else if (cmd.includes('memory')) {
          output = 'Memory utilization: 45%\nTotal: 8192 MB\nUsed: 3686 MB';
        } else {
          output = 'Display commands: version, interface, cpu, memory';
        }
      } else if (isMikrotik && cmd.startsWith('/')) {
        if (cmd === '/export') {
          output = '# Mikrotik Config Export\n/interface bridge add name=bridge1\n/ip address add address=' + tab.ip + '/24 interface=ether1';
        } else if (cmd === '/system resource') {
          output = 'uptime: 5d12h34m\nversion: 7.10\nfree-memory: 4506 MiB\ntotal-memory: 8192 MiB\ncpu-load: 15%';
        } else if (cmd === '/interface print') {
          output = 'Flags: R - running\n #    NAME           TYPE\n 0  R ether1         ether\n 1  R ether2         ether';
        } else if (cmd === '/ppp active print') {
          output = 'Flags: R - running\n #   NAME             SERVICE   UPTIME\n 0 R user1           pppoe     2d5h30m\n 1 R user2           pppoe     1d3h15m\n\nTotal: 2 active';
        } else {
          output = 'Mikrotik commands: /export, /system resource, /interface print, /ppp active print';
        }
      } else {
        switch (cmd.split(' ')[0]) {
          case 'ls':
            output = args.includes('-la') || args.includes('-l')
              ? 'total 48\ndrwxr-xr-x  5 root root 4096 Feb 15 10:00 .\ndrwxr-xr-x 20 root root 4096 Feb 10 09:00 ..\n-rw-r--r--  1 root root  220 Feb 10 .bash_logout\n-rw-r--r--  1 root root 3771 Feb 10 .bashrc\ndrwxr-xr-x  2 root root 4096 Feb 12 .cache'
              : 'Documents  Downloads  scripts';
            break;
          case 'pwd': output = '/root'; break;
          case 'whoami': output = tab.username; break;
          case 'hostname': output = tab.name.toLowerCase().replace(/\s+/g, '-'); break;
          case 'date': output = new Date().toString(); break;
          case 'uptime': output = ' 10:30:00 up 5 days, 12:34, 1 user, load average: 0.15, 0.10, 0.05'; break;
          case 'uname': output = args.includes('-a') ? 'Linux server 5.15.0-generic x86_64 GNU/Linux' : 'Linux'; break;
          case 'free':
            output = args.includes('-h')
              ? '              total        used        free\nMem:          7.8Gi       1.2Gi       4.5Gi\nSwap:         2.0Gi          0B       2.0Gi'
              : '              total        used        free\nMem:        8192000     1234567     5432109\nSwap:       2048000           0     2048000';
            break;
          case 'df':
            output = args.includes('-h')
              ? 'Filesystem      Size  Used Avail Use%\n/dev/sda1        98G   19G   75G  21%'
              : 'Filesystem     1K-blocks    Used Available\n/dev/sda1       51475068 8234512  40610472';
            break;
          case 'ip':
            if (cmd.includes('a') || cmd.includes('addr')) {
              output = '1: lo: inet 127.0.0.1/8\n2: eth0: inet ' + tab.ip + '/24';
            } else if (cmd.includes('route')) {
              output = 'default via ' + tab.ip.substring(0, tab.ip.lastIndexOf('.')) + '.1 dev eth0';
            } else {
              output = 'Usage: ip [addr|route|link]';
            }
            break;
          case 'ifconfig':
            output = 'eth0: flags=4163  mtu 1500\n        inet ' + tab.ip + '  netmask 255.255.255.0';
            break;
          case 'ping':
            output = args[0]
              ? 'PING ' + args[0] + ': 56 bytes\n64 bytes: seq=0 ttl=56 time=12.345 ms\n64 bytes: seq=1 ttl=56 time=11.234 ms\n3 packets transmitted, 3 received, 0% loss'
              : 'ping: destination required';
            break;
          case 'netstat':
            output = 'Active connections\ntcp   0.0.0.0:22    LISTEN\ntcp   0.0.0.0:80    LISTEN\ntcp   0.0.0.0:443   LISTEN';
            break;
          case 'ps':
            output = args.includes('aux')
              ? 'USER   PID %CPU %MEM COMMAND\nroot     1  0.0  0.1 /sbin/init\nroot   450  0.0  0.3 sshd'
              : 'PID TTY TIME CMD\n1234 pts/0 00:00 bash';
            break;
          case 'cat':
            if (args[0] === '/etc/passwd') output = 'root:x:0:0:root:/root:/bin/bash\nwww-data:x:33:33:www-data:/var/www';
            else if (args[0] === '/etc/hosts') output = '127.0.0.1   localhost\n127.0.1.1   server';
            else output = 'cat: ' + (args[0] || 'file') + ': No such file';
            break;
          case 'systemctl':
            output = 'ssh.service - OpenSSH Server\n   Loaded: loaded\n   Active: active (running)';
            break;
          case 'history':
            output = '1  ls -la\n2  pwd\n3  whoami\n4  uptime';
            break;
          case 'clear':
            setTabs(prev => prev.map(t => t.id === tabId ? { ...t, output: [] } : t));
            appendOutput(tabId, tab.username + '@' + tab.name + ':~$ ');
            return;
          case 'exit':
          case 'quit':
            closeTab(tabId);
            return;
          case 'help':
            output = '=== COMANDOS DISPONIVEIS ===\n\nNavegacao:\n  ls [-la]   pwd   cd <dir>\n\nSistema:\n  whoami   hostname   date   uptime\n  free -h  df -h     ps aux\n\nRede:\n  ip a     ifconfig   ping <host>\n  netstat -tuln\n\nMikrotik:\n  /export   /system resource\n  /interface print   /ppp active print\n\nHuawei:\n  display version\n  display interface\n  display cpu\n\nOutros:\n  history  clear  exit';
            break;
          case '':
            break;
          default:
            output = 'Comando nao encontrado: ' + cmd.split(' ')[0] + '\nDigite "help" para ajuda';
        }
      }

      if (output) appendOutput(tabId, output);
      appendOutput(tabId, '');
      appendOutput(tabId, tab.username + '@' + tab.name + ':~$ ');
    }, 100);
  };

  const closeTab = (tabId, e) => {
    if (e) e.stopPropagation();
    setTabs(prev => {
      const newTabs = prev.filter(t => t.id !== tabId);
      if (activeTab === tabId && newTabs.length > 0) setActiveTab(newTabs[newTabs.length - 1].id);
      else if (newTabs.length === 0) setActiveTab(null);
      return newTabs;
    });
  };

  const handleKeyDown = (e, tabId) => {
    const tab = tabs.find(t => t.id === tabId);
    if (!tab) return;

    if (e.key === 'Enter') {
      sendCommand(tabId, e.target.value);
      e.target.value = '';
    } else if (e.key === 'Tab') {
      e.preventDefault();
      const completions = findCompletions(e.target.value);
      if (completions.length === 1) {
        e.target.value = completions[0] + ' ';
      } else if (completions.length > 1) {
        appendOutput(tabId, '');
        appendOutput(tabId, 'Opcoes: ' + completions.slice(0, 8).join('  '));
        appendOutput(tabId, tab.username + '@' + tab.name + ':~$ ' + e.target.value);
      }
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      if (tab.history.length > 0) {
        const idx = tab.historyIndex < tab.history.length - 1 ? tab.historyIndex + 1 : tab.historyIndex;
        setTabs(prev => prev.map(t => t.id === tabId ? { ...t, historyIndex: idx } : t));
        e.target.value = tab.history[tab.history.length - 1 - idx] || '';
      }
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      if (tab.historyIndex > 0) {
        const idx = tab.historyIndex - 1;
        setTabs(prev => prev.map(t => t.id === tabId ? { ...t, historyIndex: idx } : t));
        e.target.value = tab.history[tab.history.length - 1 - idx] || '';
      } else {
        setTabs(prev => prev.map(t => t.id === tabId ? { ...t, historyIndex: -1 } : t));
        e.target.value = '';
      }
    } else if (e.ctrlKey && e.key === 'c') {
      appendOutput(tabId, '^C');
      appendOutput(tabId, tab.username + '@' + tab.name + ':~$ ');
      e.target.value = '';
    } else if (e.ctrlKey && e.key === 'l') {
      e.preventDefault();
      setTabs(prev => prev.map(t => t.id === tabId ? { ...t, output: [] } : t));
      appendOutput(tabId, tab.username + '@' + tab.name + ':~$ ');
    }
  };

  const currentTab = tabs.find(t => t.id === activeTab);

  return (
    <div className="flex flex-col h-[calc(100vh-150px)] bg-gray-900 rounded-lg overflow-hidden border border-gray-700">
      <div className="flex items-center bg-gray-800 border-b border-gray-700">
        <div className="flex-1 flex overflow-x-auto">
          {tabs.map(tab => (
            <div key={tab.id} onClick={() => setActiveTab(tab.id)}
              className={`flex items-center px-4 py-3 cursor-pointer border-r border-gray-700 ${activeTab === tab.id ? 'bg-gray-900 text-white border-t-2 border-t-blue-500' : 'text-gray-400 hover:bg-gray-700'}`}>
              <span className="w-2 h-2 rounded-full bg-green-500 mr-2"></span>
              <span className="text-sm">{tab.name}</span>
              <button onClick={(e) => closeTab(tab.id, e)} className="ml-2 text-gray-500 hover:text-red-400">x</button>
            </div>
          ))}
        </div>
        <button onClick={() => setShowDeviceList(!showDeviceList)} className="px-4 py-3 text-gray-400 hover:text-white">+</button>
      </div>

      {showDeviceList && (
        <div className="absolute top-32 right-8 w-72 bg-gray-800 border border-gray-700 rounded-lg shadow-xl z-50 max-h-80 overflow-y-auto">
          <div className="p-3 border-b border-gray-700 text-white">Selecionar Dispositivo</div>
          <div className="p-2">
            {devices.map(device => (
              <button key={device.id} onClick={() => openNewTab(device)} className="w-full p-3 rounded hover:bg-gray-700 text-left">
                <p className="text-white">{device.hostname}</p>
                <p className="text-gray-400 text-sm">{device.ip_address}:{device.port || 22}</p>
              </button>
            ))}
          </div>
        </div>
      )}

      {currentTab ? (
        <div className="flex-1 p-4 font-mono text-sm overflow-y-auto cursor-text" id={'terminal-' + currentTab.id} onClick={() => inputRef.current?.focus()}>
          {currentTab.output.map((line, i) => <div key={i} className="whitespace-pre-wrap text-green-400">{line}</div>)}
          <input ref={inputRef} type="text" className="w-full bg-transparent text-green-400 outline-none" onKeyDown={(e) => handleKeyDown(e, currentTab.id)} autoFocus />
        </div>
      ) : (
        <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
          <div className="text-5xl mb-4">{'>>_'}</div>
          <h3 className="text-xl text-white mb-2">Terminal SSH</h3>
          <p className="mb-4">Clique + para nova conexao</p>
          <button onClick={() => setShowDeviceList(true)} className="px-6 py-3 bg-blue-600 text-white rounded-lg">Nova Conexao</button>
        </div>
      )}

      {currentTab && (
        <div className="flex justify-between px-4 py-2 bg-gray-800 border-t border-gray-700 text-xs text-gray-400">
          <span>{currentTab.ip}:{currentTab.port} | {currentTab.username}</span>
          <span>TAB: completar | ↑↓: historico | Ctrl+L: limpar</span>
        </div>
      )}
    </div>
  );
};

export default Terminal;
